let stripeCheckout=function(){wp.hooks.addAction("wu_on_form_success","nextpress/wp-ultimo",function(t,e){"stripe-checkout"===t.gateway&&"free"!==e.gateway.slug&&e.gateway.data&&e.gateway.data.stripe_session_id&&(t.prevent_submission=!0,t=e.gateway.data.stripe_checkout_url,window.location.href=t||"https://checkout.stripe.com/pay/"+e.gateway.data.stripe_session_id)})};wp.hooks.addAction("wu_checkout_loaded","nextpress/wp-ultimo",function(){stripeCheckout()});